 1→use axum::extract::FromRequestParts;
 2→use axum::http::request::Parts;
 3→use axum::response::Redirect;
 4→use tower_sessions::Session;
 5→use uuid::Uuid;
 6→
 7→use crate::domain::UserId;
 8→
 9→/// Extractor that requires authentication.
10→/// If the user is not authenticated, redirects to /login.
11→pub struct AuthenticatedUser(pub UserId);
12→
13→impl<S> FromRequestParts<S> for AuthenticatedUser
14→where
15→    S: Send + Sync,
16→{
17→    type Rejection = Redirect;
18→
19→    async fn from_request_parts(parts: &mut Parts, state: &S) -> Result<Self, Self::Rejection> {
20→        let session = Session::from_request_parts(parts, state)
21→            .await
22→            .map_err(|_| Redirect::to("/login"))?;
23→
24→        let user_id: Option<String> = session
25→            .get("user_id")
26→            .await
27→            .map_err(|_| Redirect::to("/login"))?;
28→
29→        match user_id {
30→            Some(id_str) => {
31→                let uuid = Uuid::parse_str(&id_str).map_err(|_| Redirect::to("/login"))?;
32→                Ok(AuthenticatedUser(UserId::from_uuid(uuid)))
33→            }
34→            None => Err(Redirect::to("/login")),
35→        }
36→    }
37→}
