use chrono::{DateTime, Utc};
use uuid::Uuid;

use super::user::UserId;

const MAX_TITLE_LENGTH: usize = 300;

/// Uniquely identifies an inbox item.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct InboxItemId(Uuid);

impl Default for InboxItemId {
    fn default() -> Self {
        Self::new()
    }
}

impl InboxItemId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

/// A validated inbox item title. Non-empty after trim, max 300 characters.
#[derive(Debug, Clone, PartialEq)]
pub struct InboxItemTitle(String);

impl InboxItemTitle {
    pub fn parse(input: String) -> Result<Self, InboxItemTitleError> {
        let trimmed = input.trim().to_string();
        if trimmed.is_empty() {
            return Err(InboxItemTitleError::Empty);
        }
        if trimmed.len() > MAX_TITLE_LENGTH {
            return Err(InboxItemTitleError::TooLong {
                max: MAX_TITLE_LENGTH,
                actual: trimmed.len(),
            });
        }
        Ok(Self(trimmed))
    }

    pub fn as_str(&self) -> &str {
        &self.0
    }
}

#[derive(Debug, thiserror::Error, PartialEq)]
pub enum InboxItemTitleError {
    #[error("Inbox item title cannot be empty")]
    Empty,
    #[error("Inbox item title too long (max {max}, got {actual})")]
    TooLong { max: usize, actual: usize },
}

/// A raw, unclarified capture in the GTD inbox.
#[derive(Debug, Clone)]
pub struct InboxItem {
    id: InboxItemId,
    user_id: UserId,
    title: InboxItemTitle,
    created_at: DateTime<Utc>,
}

impl InboxItem {
    pub fn new(user_id: UserId, title: InboxItemTitle) -> Self {
        Self {
            id: InboxItemId::new(),
            user_id,
            title,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: InboxItemId,
        user_id: UserId,
        title: InboxItemTitle,
        created_at: DateTime<Utc>,
    ) -> Self {
        Self {
            id,
            user_id,
            title,
            created_at,
        }
    }

    pub fn id(&self) -> &InboxItemId {
        &self.id
    }

    pub fn user_id(&self) -> &UserId {
        &self.user_id
    }

    pub fn title(&self) -> &InboxItemTitle {
        &self.title
    }

    pub fn created_at(&self) -> &DateTime<Utc> {
        &self.created_at
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn valid_title_is_accepted() {
        let result = InboxItemTitle::parse("Buy groceries".to_string());
        assert!(result.is_ok());
        assert_eq!(result.unwrap().as_str(), "Buy groceries");
    }

    #[test]
    fn empty_title_is_rejected() {
        let result = InboxItemTitle::parse("".to_string());
        assert_eq!(result, Err(InboxItemTitleError::Empty));
    }

    #[test]
    fn whitespace_only_title_is_rejected() {
        let result = InboxItemTitle::parse("   ".to_string());
        assert_eq!(result, Err(InboxItemTitleError::Empty));
    }

    #[test]
    fn title_is_trimmed() {
        let result = InboxItemTitle::parse("  Buy groceries  ".to_string());
        assert!(result.is_ok());
        assert_eq!(result.unwrap().as_str(), "Buy groceries");
    }

    #[test]
    fn title_at_max_length_is_accepted() {
        let title = "a".repeat(MAX_TITLE_LENGTH);
        let result = InboxItemTitle::parse(title.clone());
        assert!(result.is_ok());
        assert_eq!(result.unwrap().as_str(), title);
    }

    #[test]
    fn title_exceeding_max_length_is_rejected() {
        let title = "a".repeat(MAX_TITLE_LENGTH + 1);
        let result = InboxItemTitle::parse(title);
        assert_eq!(
            result,
            Err(InboxItemTitleError::TooLong {
                max: MAX_TITLE_LENGTH,
                actual: MAX_TITLE_LENGTH + 1,
            })
        );
    }

    #[test]
    fn title_with_special_characters_is_accepted() {
        let result = InboxItemTitle::parse("Buy milk & eggs <3".to_string());
        assert!(result.is_ok());
        assert_eq!(result.unwrap().as_str(), "Buy milk & eggs <3");
    }

    #[test]
    fn new_creates_inbox_item_with_given_user_and_title() {
        let user_id = UserId::new();
        let title = InboxItemTitle::parse("Call dentist".to_string()).unwrap();
        let item = InboxItem::new(user_id.clone(), title);

        assert_eq!(item.user_id(), &user_id);
        assert_eq!(item.title().as_str(), "Call dentist");
    }
}

