  1→use askama::Template;
  2→use axum::extract::{Path, State};
  3→use axum::http::{HeaderMap, StatusCode};
  4→use axum::response::{Html, IntoResponse, Redirect, Response};
  5→use axum::Form;
  6→use sqlx::PgPool;
  7→use uuid::Uuid;
  8→
  9→use super::auth::AuthenticatedUser;
 10→use crate::domain::{InboxItem, InboxItemId};
 11→use crate::services::inbox_service::{
 12→    capture_inbox_item, delete_inbox_item, get_inbox_count, get_inbox_items, CaptureInboxError,
 13→    DeleteInboxError,
 14→};
 15→
 16→fn is_htmx_request(headers: &HeaderMap) -> bool {
 17→    headers.contains_key("hx-request")
 18→}
 19→
 20→fn htmx_response_with_announce(body: Html<String>, message: &str) -> Response {
 21→    let trigger_json = format!(r#"{{"announce":"{}"}}"#, message);
 22→    (
 23→        [(
 24→            axum::http::header::HeaderName::from_static("hx-trigger"),
 25→            axum::http::HeaderValue::from_str(&trigger_json).unwrap(),
 26→        )],
 27→        body,
 28→    )
 29→        .into_response()
 30→}
 31→
 32→pub struct InboxItemView {
 33→    pub id: String,
 34→    pub title: String,
 35→}
 36→
 37→impl From<&InboxItem> for InboxItemView {
 38→    fn from(item: &InboxItem) -> Self {
 39→        Self {
 40→            id: item.id().as_uuid().to_string(),
 41→            title: item.title().as_str().to_string(),
 42→        }
 43→    }
 44→}
 45→
 46→#[derive(Template)]
 47→#[template(path = "inbox.html")]
 48→struct InboxTemplate {
 49→    current_page: &'static str,
 50→    inbox_count: i64,
 51→    items: Vec<InboxItemView>,
 52→}
 53→
 54→#[derive(Template)]
 55→#[template(path = "inbox_item.html")]
 56→struct InboxItemTemplate {
 57→    item: InboxItemView,
 58→}
 59→
 60→pub async fn get_inbox(
 61→    AuthenticatedUser(user_id): AuthenticatedUser,
 62→    State(pool): State<PgPool>,
 63→) -> Result<impl IntoResponse, InboxError> {
 64→    let items = get_inbox_items(&pool, &user_id)
 65→        .await
 66→        .map_err(InboxError::Unexpected)?;
 67→
 68→    let inbox_count = items.len() as i64;
 69→    let item_views: Vec<InboxItemView> = items.iter().map(InboxItemView::from).collect();
 70→
 71→    let template = InboxTemplate {
 72→        current_page: "inbox",
 73→        inbox_count,
 74→        items: item_views,
 75→    };
 76→    Ok(Html(template.render()?))
 77→}
 78→
 79→#[derive(serde::Deserialize)]
 80→pub struct CaptureForm {
 81→    pub title: String,
 82→}
 83→
 84→pub async fn post_inbox(
 85→    AuthenticatedUser(user_id): AuthenticatedUser,
 86→    State(pool): State<PgPool>,
 87→    headers: HeaderMap,
 88→    Form(form): Form<CaptureForm>,
 89→) -> Result<Response, InboxError> {
 90→    let htmx = is_htmx_request(&headers);
 91→
 92→    // Silently ignore empty/whitespace-only submissions
 93→    if form.title.trim().is_empty() {
 94→        if htmx {
 95→            return Ok(StatusCode::NO_CONTENT.into_response());
 96→        }
 97→        return Ok(Redirect::to("/inbox").into_response());
 98→    }
 99→
100→    match capture_inbox_item(&pool, user_id.clone(), form.title).await {
101→        Ok(item) => {
102→            if htmx {
103→                let template = InboxItemTemplate {
104→                    item: InboxItemView::from(&item),
105→                };
106→                let body = template.render().map_err(InboxError::Render)?;
107→                Ok(htmx_response_with_announce(Html(body), "Captured to inbox"))
108→            } else {
109→                Ok(Redirect::to("/inbox").into_response())
110→            }
111→        }
112→        Err(CaptureInboxError::InvalidTitle(title_err)) => {
113→            let user_facing = match title_err {
114→                crate::domain::TodoTitleError::Empty => {
115→                    if htmx {
116→                        return Ok(StatusCode::NO_CONTENT.into_response());
117→                    }
118→                    return Ok(Redirect::to("/inbox").into_response());
119→                }
120→                crate::domain::TodoTitleError::TooLong { max, .. } => {
121→                    format!("That title is too long (max {max} characters)")
122→                }
123→            };
124→
125→            let items = get_inbox_items(&pool, &user_id)
126→                .await
127→                .map_err(InboxError::Unexpected)?;
128→            let inbox_count = items.len() as i64;
129→            let item_views: Vec<InboxItemView> = items.iter().map(InboxItemView::from).collect();
130→
131→            let template = InboxTemplate {
132→                current_page: "inbox",
133→                inbox_count,
134→                items: item_views,
135→            };
136→            let _ = user_facing; // Title too long error is shown via template if needed
137→            let body = template.render().map_err(InboxError::Render)?;
138→            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
139→        }
140→        Err(CaptureInboxError::Unexpected(err)) => Err(InboxError::Unexpected(err)),
141→    }
142→}
143→
144→pub async fn post_delete_inbox_item(
145→    AuthenticatedUser(user_id): AuthenticatedUser,
146→    State(pool): State<PgPool>,
147→    headers: HeaderMap,
148→    Path(item_id): Path<Uuid>,
149→) -> Result<Response, InboxError> {
150→    let htmx = is_htmx_request(&headers);
151→    let inbox_item_id = InboxItemId::from_uuid(item_id);
152→
153→    match delete_inbox_item(&pool, &inbox_item_id, &user_id).await {
154→        Ok(()) => {
155→            if htmx {
156→                Ok(htmx_response_with_announce(
157→                    Html(String::new()),
158→                    "Inbox item deleted",
159→                ))
160→            } else {
161→                Ok(Redirect::to("/inbox").into_response())
162→            }
163→        }
164→        Err(DeleteInboxError::NotFound) => Ok((
165→            StatusCode::NOT_FOUND,
166→            Html("<h1>Inbox item not found</h1>".to_string()),
167→        )
168→            .into_response()),
169→        Err(DeleteInboxError::Unauthorized) => Ok((
170→            StatusCode::FORBIDDEN,
171→            Html("<h1>Not authorized</h1>".to_string()),
172→        )
173→            .into_response()),
174→        Err(DeleteInboxError::Unexpected(err)) => Err(InboxError::Unexpected(err)),
175→    }
176→}
177→
